// ── THRESHOLD ──
function updateThreshold(){ document.getElementById("threshDisplay").textContent=(parseInt(document.getElementById("threshold").value)||0)+"%"; }

// ── QUESTION EDITOR ──
function addQuestion(data){
  const list=document.getElementById("questionsList");
  const idx=list.children.length;
  const q=data||{text:"",options:[{text:"",correct:false},{text:"",correct:false}]};
  const div=document.createElement("div"); div.className="q-item";
  div.innerHTML=
    '<div class="q-item-header"><span class="q-num">'+T.qLabel+" "+(idx+1)+'</span>'+
    '<button class="btn-icon" onclick="removeQuestion(this)" title="'+T.btnDelQ+'">&#x1F5D1;</button></div>'+
    '<input type="text" class="q-text-input" placeholder="'+T.qPh+'" value="'+esc(q.text)+'">'+
    '<label style="margin-top:10px">'+T.ansLabel+' <span style="font-weight:300;text-transform:none;letter-spacing:0">'+T.ansHint+'</span></label>'+
    '<div class="options-list"></div>'+
    '<button class="btn-add-option" onclick="addOpt(this)">'+T.btnAddOpt+'</button>';
  list.appendChild(div);
  q.options.forEach(o=>addOpt(div.querySelector(".btn-add-option"),o));
  renumber();
}
function addOpt(btn,data){
  const ol=btn.previousElementSibling;
  const o=data||{text:"",correct:false};
  const row=document.createElement("div"); row.className="option-row";
  row.innerHTML='<button class="option-correct-btn'+(o.correct?" correct":"")+'" onclick="toggleC(this)">'+(o.correct?"&#10003;":"")+'</button>'+
    '<input type="text" placeholder="'+T.ansPh+'" value="'+esc(o.text)+'">'+
    '<button class="btn-icon" onclick="this.parentElement.remove()" title="'+T.btnDelOpt+'">&#x2715;</button>';
  ol.appendChild(row);
}
function toggleC(btn){ btn.classList.toggle("correct"); btn.innerHTML=btn.classList.contains("correct")?"&#10003;":""; }
function removeQuestion(btn){ btn.closest(".q-item").remove(); renumber(); }
function renumber(){
  document.querySelectorAll(".q-item").forEach((el,i)=>{
    el.querySelector(".q-num").textContent=T.qLabel+" "+(i+1);
    el.querySelector(".q-text-input").placeholder=T.qPh;
    el.querySelectorAll(".option-row input[type=text]").forEach(inp=>inp.placeholder=T.ansPh);
    const ab=el.querySelector(".btn-add-option"); if(ab) ab.textContent=T.btnAddOpt;
  });
}
function clearForm(){
  editingId=null;
  document.getElementById("testName").value="";
  document.getElementById("testDesc").value="";
  document.getElementById("threshold").value=70; updateThreshold();
  document.getElementById("questionsList").innerHTML="";
  document.getElementById("btnSave").textContent=T.btnSave;
  addQuestion();
}
function fillForm(t){
  editingId=t.id||null;
  document.getElementById("testName").value=t.name||"";
  document.getElementById("testDesc").value=t.desc||"";
  document.getElementById("threshold").value=t.threshold||70; updateThreshold();
  document.getElementById("questionsList").innerHTML="";
  (t.questions||[]).forEach(q=>addQuestion(q));
  if(editingId) document.getElementById("btnSave").textContent=T.toastUpdated("").replace("✅ ","💾 ").replace(/ ".*"!$/,"");
  window.scrollTo({top:0,behavior:"smooth"});
}
function collectForm(){
  const questions=[];
  document.querySelectorAll(".q-item").forEach(qEl=>{
    const text=qEl.querySelector(".q-text-input").value.trim();
    const options=[];
    qEl.querySelectorAll(".option-row").forEach(row=>{
      const t=row.querySelector("input[type=text]").value.trim();
      const correct=row.querySelector(".option-correct-btn").classList.contains("correct");
      if(t) options.push({text:t,correct});
    });
    if(text&&options.length>=2) questions.push({text,options});
  });
  return{
    name:document.getElementById("testName").value.trim(),
    desc:document.getElementById("testDesc").value.trim(),
    threshold:parseInt(document.getElementById("threshold").value)||70,
    questions
  };
}
function validateForm(t){
  if(!t.name){alert(T.alertNoName);return false;}
  if(!t.questions.length){alert(T.alertNoQ);return false;}
  for(let i=0;i<t.questions.length;i++)
    if(!t.questions[i].options.some(o=>o.correct)){alert(T.alertNoCorrect(i+1));return false;}
  return true;
}

// ── SAVE / EDIT / DELETE ──
function saveTest(){
  const t=collectForm(); if(!validateForm(t))return;
  if(editingId!==null){
    const idx=tests.findIndex(x=>x.id===editingId);
    if(idx>=0){tests[idx]={...t,id:editingId}; toast(T.toastUpdated(t.name),"success");}
    editingId=null;
  } else {
    t.id=Date.now(); tests.push(t); toast(T.toastSaved(t.name),"success");
  }
  saveKataloog(); renderTestList(); clearForm();
}
function editTest(id){
  const t=tests.find(x=>x.id===id); if(!t)return;
  fillForm(t);
  document.getElementById("btnSave").textContent=T.editMode;
}
function deleteTest(id){
  const t=tests.find(x=>x.id===id); if(!t)return;
  if(!confirm(T.confirmDelete(t.name)))return;
  tests=tests.filter(x=>x.id!==id);
  toast(T.toastDeleted(t.name));
  saveKataloog(); renderTestList();
  if(editingId===id) clearForm();
}

// ── RENDER LIST ──
function renderTestList(){
  const el=document.getElementById("testList");
  if(!tests.length){el.innerHTML='<div class="empty-state">'+T.noTests+'</div>';return;}
  el.innerHTML="";
  tests.forEach(t=>{
    const row=document.createElement("div"); row.className="test-row";
    row.innerHTML=
      '<div class="test-row-info">'+
        '<div class="test-row-name">'+esc(t.name)+'</div>'+
        '<div class="test-row-meta">'+T.metaQ(t.questions.length,t.threshold)+'</div>'+
      '</div>'+
      '<div class="test-row-actions">'+
        '<button class="btn btn-outline btn-sm" onclick="editTest('+t.id+')">'+T.btnEdit+'</button>'+
        '<button class="btn btn-primary btn-sm" onclick="pushToGithub('+t.id+')">'+T.btnGh+'</button>'+
        '<button class="btn btn-danger btn-sm" onclick="deleteTest('+t.id+')">'+T.btnDelete+'</button>'+
      '</div>';
    el.appendChild(row);
  });
}

// ── GITHUB PUSH ──
const GH_REPO = "madislaansalu/koolitustestid";
const GH_BRANCH = "main";

function ghFilename(name){
  return name.toLowerCase()
    .replace(/ä/g,"a").replace(/ö/g,"o").replace(/ü/g,"u").replace(/õ/g,"o")
    .replace(/[^a-z0-9\s-]/g,"").trim().replace(/\s+/g,"-") + ".html";
}
function getGhToken(){
  let t=localStorage.getItem("gh_token");
  if(!t){
    t=prompt("GitHub Personal Access Token (vajab 'repo' õigust):\n(salvestatakse brauserisse)");
    if(t) localStorage.setItem("gh_token",t.trim());
  }
  return t?t.trim():null;
}
async function pushToGithub(id){
  const t=tests.find(x=>x.id===id); if(!t)return;
  const token=getGhToken(); if(!token)return;
  const filename=ghFilename(t.name);
  const html=getTestHtml();
  const placeholder="/*%%TESTS_DATA%%*/\nconst EMBEDDED_TESTS=[];";
  const replacement="/*%%TESTS_DATA%%*/\nconst EMBEDDED_TESTS="+JSON.stringify([t])+";";
  const out=html.includes("/*%%TESTS_DATA%%*/")
    ?html.replace(placeholder,replacement)
    :html.replace("const EMBEDDED_TESTS=[];","const EMBEDDED_TESTS="+JSON.stringify([t])+";");
  const apiUrl=`https://api.github.com/repos/${GH_REPO}/contents/${filename}`;
  const headers={"Authorization":"token "+token,"Content-Type":"application/json"};
  let sha=null;
  try{
    const check=await fetch(apiUrl,{headers});
    if(check.ok){
      sha=(await check.json()).sha;
      if(!confirm(`Fail "${filename}" on juba kataloogis. Kirjutan üle?`))return;
    } else if(check.status===401){
      localStorage.removeItem("gh_token");
      return pushToGithub(id);
    } else if(check.status!==404){
      toast("❌ GitHub viga: "+check.status,"error");
      return;
    }
  } catch(e){toast("❌ Ühenduse viga","error");return;}
  const content=btoa(unescape(encodeURIComponent(out)));
  const body={message:"Lisa test: "+t.name,content,branch:GH_BRANCH,...(sha?{sha}:{})};
  try{
    const res=await fetch(apiUrl,{method:"PUT",headers,body:JSON.stringify(body)});
    if(res.ok) toast("✅ "+filename+" salvestatud GitHubi!","success");
    else{const err=await res.json(); toast("❌ "+(err.message||res.status),"error");}
  } catch(e){toast("❌ Ühenduse viga","error");}
}

// ── GITHUB KATALOOG ──
const GH_EXCLUDE = new Set(["admin.html","index.html","admin (6).html","toiduhygieen_test.html","toiduhygieen_test (1).html","toiduhygieen_ru (1).html","Toituhügeenikoolitus2026-04-13.html"]);

async function loadGhCatalog(){
  const el=document.getElementById("ghCatalogList");
  el.innerHTML='<div class="empty-state" style="font-size:.85rem">Laen...</div>';
  try{
    const res=await fetch(`https://api.github.com/repos/${GH_REPO}/contents/?ref=${GH_BRANCH}`);
    if(!res.ok){el.innerHTML='<div class="empty-state">❌ Viga: '+res.status+'</div>';return;}
    const files=await res.json();
    const htmlFiles=files.filter(f=>f.name.endsWith(".html")&&!GH_EXCLUDE.has(f.name));
    if(!htmlFiles.length){el.innerHTML='<div class="empty-state">Kataloogis pole veel teste.</div>';return;}
    el.innerHTML="";
    htmlFiles.forEach(f=>{
      const row=document.createElement("div"); row.className="test-row";
      const displayName=f.name.replace(/-/g," ").replace(/\.html$/,"");
      const url=`https://madislaansalu.github.io/koolitustestid/${f.name}`;
      row.innerHTML=
        '<div class="test-row-info">'+
          '<div class="test-row-name">'+esc(displayName)+'</div>'+
          '<div class="test-row-meta">'+f.name+'</div>'+
        '</div>'+
        '<div class="test-row-actions">'+
          '<a class="btn btn-outline btn-sm" href="'+url+'" target="_blank">🔗 Ava</a>'+
          '<button class="btn btn-primary btn-sm" onclick="importFromGh(\''+encodeURIComponent(f.download_url)+'\',\''+esc(f.name)+'\')">⬇ Laadi kataloogi</button>'+
        '</div>';
      el.appendChild(row);
    });
  } catch(e){el.innerHTML='<div class="empty-state">❌ Ühenduse viga</div>';}
}

async function importFromGh(encodedUrl, filename){
  try{
    const res=await fetch(decodeURIComponent(encodedUrl));
    if(!res.ok){toast("❌ Viga faili laadimisel","error");return;}
    const html=await res.text();
    const m=html.match(/const EMBEDDED_TESTS=(\[[\s\S]*?\]);/);
    if(!m) throw new Error();
    const imported=JSON.parse(m[1]);
    if(!Array.isArray(imported)) throw new Error();
    let added=0;
    imported.forEach(t=>{if(!tests.find(x=>x.id===t.id)){tests.push(t);added++;}});
    saveKataloog(); renderTestList();
    toast(added?"✅ "+added+" testi laaditud kataloogi":"ℹ️ Test juba kataloogis","success");
  } catch(e){toast("❌ Faili lugemine ebaõnnestus","error");}
}

// ── EXPORT test.html ──
function exportTestFile(){
  if(!tests.length){alert(T.alertNoQ);return;}
  // Decode base64 template
  const html=getTestHtml();
  // Inject tests data — replace the placeholder line
  const placeholder="/*%%TESTS_DATA%%*/\nconst EMBEDDED_TESTS=[];";
  const replacement="/*%%TESTS_DATA%%*/\nconst EMBEDDED_TESTS="+JSON.stringify(tests)+";";
  const out=html.includes("/*%%TESTS_DATA%%*/")
    ? html.replace(placeholder,replacement)
    : html.replace("const EMBEDDED_TESTS=[];","const EMBEDDED_TESTS="+JSON.stringify(tests)+";");
  const blob=new Blob([out],{type:"text/html;charset=utf-8"});
  const a=document.createElement("a");
  a.href=URL.createObjectURL(blob); a.download="test.html"; a.click();
  URL.revokeObjectURL(a.href);
  toast(T.toastExported,"success");
}

// ── IMPORT test.html ──
function importTestFile(input){
  const file=input.files[0]; if(!file)return; input.value="";
  const r=new FileReader();
  r.onload=e=>{
    try{
      const html=e.target.result;
      const m=html.match(/const EMBEDDED_TESTS=(\[[\s\S]*?\]);/);
      if(!m) throw new Error("no marker");
      const imported=JSON.parse(m[1]);
      if(!Array.isArray(imported)) throw new Error("not array");
      let added=0;
      imported.forEach(t=>{
        if(!tests.find(x=>x.id===t.id)){tests.push(t);added++;}
      });
      saveKataloog(); renderTestList();
      toast(T.toastImported(added),"success");
    } catch(e){ toast(T.toastBadFile,"error"); }
  };
  r.readAsText(file);
}

